import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder rawInput = new StringBuilder();
        String line;
        while ((line = br.readLine()) != null) {
            rawInput.append(line).append(' ');
        }
        // Replace escaped newlines ("\\n") with spaces to treat them as delimiters
        String all = rawInput.toString().replace("\\n", " ");
        StringTokenizer st = new StringTokenizer(all);
        StringBuilder sb = new StringBuilder();
        int T = Integer.parseInt(st.nextToken());
        while (T-- > 0) {
            int N = Integer.parseInt(st.nextToken());
            int M = Integer.parseInt(st.nextToken());
            long H = Long.parseLong(st.nextToken());
            long[] cars = new long[N];
            long[] energies = new long[M];
            for (int i = 0; i < N; i++) {
                cars[i] = Long.parseLong(st.nextToken());
            }
            for (int i = 0; i < M; i++) {
                long b = Long.parseLong(st.nextToken());
                energies[i] = b * H; // total energy each outlet can provide
            }
            Arrays.sort(cars);
            Arrays.sort(energies);
            long total = 0;
            int i = N - 1, j = M - 1;
            while (i >= 0 && j >= 0) {
                total += Math.min(cars[i], energies[j]);
                i--;
                j--;
            }
            sb.append(total).append('\n');
        }
        System.out.print(sb.toString());
    }
}

